import{_ as e,c as t,o as r,ae as i}from"./chunks/framework.B7Y1jjX-.js";const m=JSON.parse('{"title":"1.1 计算机发展","description":"","frontmatter":{},"headers":[],"relativePath":"notes/学习/408/计算机组成原理/第一章 计算机系统概述.md","filePath":"notes/学习/408/计算机组成原理/第一章 计算机系统概述.md"}'),h={name:"notes/学习/408/计算机组成原理/第一章 计算机系统概述.md"};function n(o,a,d,l,s,p){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="_1-1-计算机发展" tabindex="-1">1.1 计算机发展 <a class="header-anchor" href="#_1-1-计算机发展" aria-label="Permalink to &quot;1.1 计算机发展&quot;">​</a></h1><h2 id="_1-1-1-计算机系统" tabindex="-1">1.1.1 计算机系统 <a class="header-anchor" href="#_1-1-1-计算机系统" aria-label="Permalink to &quot;1.1.1 计算机系统&quot;">​</a></h2><h3 id="软件" tabindex="-1">软件 <a class="header-anchor" href="#软件" aria-label="Permalink to &quot;软件&quot;">​</a></h3><p>![[Pasted image 20251111195855.png]]</p><h3 id="硬件" tabindex="-1">硬件 <a class="header-anchor" href="#硬件" aria-label="Permalink to &quot;硬件&quot;">​</a></h3><p>![[Pasted image 20251111200219.png]]</p><p>![[Pasted image 20251111200901.png]]</p><p>![[Pasted image 20251111201153.png]]</p><p>![[Pasted image 20251111201300.png]] （此小节408大纲不考）</p><h1 id="_1-2-计算机结构" tabindex="-1">1.2 计算机结构 <a class="header-anchor" href="#_1-2-计算机结构" aria-label="Permalink to &quot;1.2 计算机结构&quot;">​</a></h1><h2 id="_1-2-1-计算机硬件基本结构" tabindex="-1">1.2.1 计算机硬件基本结构 <a class="header-anchor" href="#_1-2-1-计算机硬件基本结构" aria-label="Permalink to &quot;1.2.1 计算机硬件基本结构&quot;">​</a></h2><h3 id="早期冯诺依曼机" tabindex="-1">早期冯诺依曼机 <a class="header-anchor" href="#早期冯诺依曼机" aria-label="Permalink to &quot;早期冯诺依曼机&quot;">​</a></h3><p>![[Pasted image 20251111202431.png]] 我们可以使用软件的方式实现乘法，而不需要专门去实现一个乘法运算单元</p><p>![[Pasted image 20251111202818.png]] 无论输入还是输出数据都要经过运算器，但本质运算器是用来处理数据而不是转运数据，这样的设计会降低效率</p><h3 id="现代计算机结构" tabindex="-1">现代计算机结构 <a class="header-anchor" href="#现代计算机结构" aria-label="Permalink to &quot;现代计算机结构&quot;">​</a></h3><p>![[Pasted image 20251111203206.png]]</p><p>现代计算机以存储器为核心，运算器+控制器=CPU ![[Pasted image 20251111203538.png]]</p><h2 id="_1-2-2-硬件工作原理" tabindex="-1">1.2.2 硬件工作原理 <a class="header-anchor" href="#_1-2-2-硬件工作原理" aria-label="Permalink to &quot;1.2.2 硬件工作原理&quot;">​</a></h2><h3 id="主存储器-内存" tabindex="-1">主存储器（内存） <a class="header-anchor" href="#主存储器-内存" aria-label="Permalink to &quot;主存储器（内存）&quot;">​</a></h3><p>![[Pasted image 20251112160142.png]] （在现代计算机中MAR与MDR被设计在CPU中）</p><h3 id="运算器" tabindex="-1">运算器 <a class="header-anchor" href="#运算器" aria-label="Permalink to &quot;运算器&quot;">​</a></h3><p>![[Pasted image 20251112160427.png]]</p><h3 id="控制器" tabindex="-1">控制器 <a class="header-anchor" href="#控制器" aria-label="Permalink to &quot;控制器&quot;">​</a></h3><p>![[Pasted image 20251112160737.png]] ![[Pasted image 20251112160758.png]]</p><h3 id="计算机工作过程" tabindex="-1">计算机工作过程 <a class="header-anchor" href="#计算机工作过程" aria-label="Permalink to &quot;计算机工作过程&quot;">​</a></h3><p>![[Pasted image 20251112161613.png]] ![[Pasted image 20251112161923.png]] ![[Pasted image 20251112162203.png]] ![[Pasted image 20251112162318.png]] ![[Pasted image 20251112162407.png]]</p><h2 id="_1-2-3-计算机软件" tabindex="-1">1.2.3 计算机软件 <a class="header-anchor" href="#_1-2-3-计算机软件" aria-label="Permalink to &quot;1.2.3 计算机软件&quot;">​</a></h2><h3 id="软件分类" tabindex="-1">软件分类 <a class="header-anchor" href="#软件分类" aria-label="Permalink to &quot;软件分类&quot;">​</a></h3><p>![[Pasted image 20251112163606.png]]</p><h3 id="语言分类" tabindex="-1">语言分类 <a class="header-anchor" href="#语言分类" aria-label="Permalink to &quot;语言分类&quot;">​</a></h3><p>![[Pasted image 20251112163458.png]]</p><h3 id="软件硬件逻辑功能的等价性" tabindex="-1">软件硬件逻辑功能的等价性 <a class="header-anchor" href="#软件硬件逻辑功能的等价性" aria-label="Permalink to &quot;软件硬件逻辑功能的等价性&quot;">​</a></h3><p>我们可以使用软件的方式来实现乘法（使用加法），也可以使用专用的硬件来实现（成本高，但性能更好） 指令集体系结构（ISA）：用来定义一台计算机所支持的指令，以及每一条指令的用法与作用是什么，是软件与硬件之间的界限，在设计ISA时要同时考虑成本与效率问题</p><h2 id="_1-2-4-计算机系统的层次结构" tabindex="-1">1.2.4 计算机系统的层次结构 <a class="header-anchor" href="#_1-2-4-计算机系统的层次结构" aria-label="Permalink to &quot;1.2.4 计算机系统的层次结构&quot;">​</a></h2><p>![[Pasted image 20251112164735.png]]</p><h2 id="_1-2-5-计算机系统工作原理" tabindex="-1">1.2.5 计算机系统工作原理 <a class="header-anchor" href="#_1-2-5-计算机系统工作原理" aria-label="Permalink to &quot;1.2.5 计算机系统工作原理&quot;">​</a></h2><p>![[Pasted image 20251112165233.png]]</p><h2 id="_1-2-6-计算机性能指标" tabindex="-1">1.2.6 计算机性能指标 <a class="header-anchor" href="#_1-2-6-计算机性能指标" aria-label="Permalink to &quot;1.2.6 计算机性能指标&quot;">​</a></h2><h3 id="存储器的性能指标" tabindex="-1">存储器的性能指标 <a class="header-anchor" href="#存储器的性能指标" aria-label="Permalink to &quot;存储器的性能指标&quot;">​</a></h3><p>![[Pasted image 20251112165715.png]]</p><h3 id="cpu的性能指标" tabindex="-1">CPU的性能指标 <a class="header-anchor" href="#cpu的性能指标" aria-label="Permalink to &quot;CPU的性能指标&quot;">​</a></h3><p>![[Pasted image 20251112170231.png]] ![[Pasted image 20251112170658.png]]</p><h3 id="系统整体性能指标" tabindex="-1">系统整体性能指标 <a class="header-anchor" href="#系统整体性能指标" aria-label="Permalink to &quot;系统整体性能指标&quot;">​</a></h3><p>![[Pasted image 20251112171029.png]] 我们可以使用基准程序来测试计算机的性能</p>',44)])])}const P=e(h,[["render",n]]);export{m as __pageData,P as default};
